import{_ as r,o as t,c as e,ag as l}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"ZG803 产品白皮书","description":"","frontmatter":{"title":"ZG803 产品白皮书"},"headers":[],"relativePath":"hardware/zg803/whitepaper.md","filePath":"hardware/zg803/whitepaper.md","lastUpdated":null}'),i={name:"hardware/zg803/whitepaper.md"};function o(n,a,s,p,h,d){return t(),e("div",null,[...a[0]||(a[0]=[l('<h2 id="目-录" tabindex="-1"><strong>目 录</strong> <a class="header-anchor" href="#目-录" aria-label="Permalink to &quot;**目 录**&quot;">​</a></h2><p>1．产品概述 2．芯片硬件配置参数 3．产品功能 4．唤醒词&amp;离线命令词 5．典型应用场景 6．合作模式</p><h1 id="产品概述" tabindex="-1">产品概述 <a class="header-anchor" href="#产品概述" aria-label="Permalink to &quot;产品概述&quot;">​</a></h1><p>ZG803集成讯飞单麦离线识别算法，支持 3~5M 远场识别，支持唤醒词、离线识别命令词和本地回复语配置。</p><h1 id="芯片硬件配置参数" tabindex="-1">芯片硬件配置参数 <a class="header-anchor" href="#芯片硬件配置参数" aria-label="Permalink to &quot;芯片硬件配置参数&quot;">​</a></h1><p><strong>CPU：</strong> 32-bit DSP，主频 160MHz <strong>SDRAM</strong>：128KB <strong>Flash:</strong> 512KB</p><h1 id="产品功能" tabindex="-1">产品功能 <a class="header-anchor" href="#产品功能" aria-label="Permalink to &quot;产品功能&quot;">​</a></h1><p><strong>语音唤醒</strong></p><ul><li>安静场景唤醒率&gt;95%</li><li>支持自定义唤醒词定制</li></ul><p><strong>离线识别</strong></p><ul><li>支持30条离线指令</li><li>支持自定义离线命令词</li><li>支持英、韩、日语、越南、印尼、西班牙等多语种识别</li></ul><p><strong>串口通信</strong></p><ul><li>支持串口下发指令，串口波特率921600</li></ul><p><strong>多种发音人</strong></p><ul><li>支持标准男生、女生等不同音色</li></ul><p><strong>客制化</strong></p><ul><li>可提供唤醒词定制工具，快速便捷实现定制</li></ul><h1 id="_4-唤醒词-离线命令词" tabindex="-1">4.．唤醒词&amp;离线命令词 <a class="header-anchor" href="#_4-唤醒词-离线命令词" aria-label="Permalink to &quot;4.．唤醒词&amp;离线命令词&quot;">​</a></h1><p>1.默认唤醒词“小飞小飞”，客户可自定义唤醒词； 2.支持免唤醒交互，即在设备未唤醒情况，直接说出离线识别命令词就可以与模组进行交互 3.支持唤醒词+离线命令词的方式交互，即先说主唤醒词将设备唤醒，然后可以进行语音交互。</p><p>优先推荐采用唤醒词+离线命令词的方式交互，10 个以内命令词可采用免唤醒交互方式。</p><h1 id="典型应用场景" tabindex="-1">典型应用场景 <a class="header-anchor" href="#典型应用场景" aria-label="Permalink to &quot;典型应用场景&quot;">​</a></h1><ul><li>智能照明</li><li>儿童玩具</li><li>茶吧机</li><li>取暖桌</li><li>智能插座 ……</li></ul><h1 id="合作模式" tabindex="-1">合作模式 <a class="header-anchor" href="#合作模式" aria-label="Permalink to &quot;合作模式&quot;">​</a></h1><p>请联系商务：<a href="mailto:aiui_support@iflytek.com" target="_blank" rel="noreferrer">aiui_support@iflytek.com</a> 1.方案商：中英文授权1KK+或者多语种授权300K+ 2.产品开发公司：方案商直接对接，讯飞开通软核算法授权</p>',24)])])}const _=r(i,[["render",o]]);export{c as __pageData,_ as default};
